-- ------------------------------------------------------------
-- 3. VERIFICACIÓN POST-INSERCIÓN
-- ------------------------------------------------------------
SELECT COUNT(*) AS total_importadas FROM transactions
  WHERE tx_source = 'import' AND tx_usr_id = '4b4146db-9487-43f9-ac6a-00a99e868856'::uuid;

SELECT tx_type, COUNT(*) AS n, ROUND(SUM(tx_amount)::numeric, 2) AS total
  FROM transactions
  WHERE tx_source = 'import' AND tx_usr_id = '4b4146db-9487-43f9-ac6a-00a99e868856'::uuid
  GROUP BY tx_type ORDER BY tx_type;

COMMIT;